resource "aws_instance" "k8_master" {
  ami                         = data.aws_ami.amazon_linux.id
  instance_type               = var.instance_type
  subnet_id                   = aws_subnet.private_subnet.id # Move to private subnet
  vpc_security_group_ids      = [aws_security_group.k8_master_sg.id]
  key_name                    = var.key_name
  associate_public_ip_address = false # Remove public IP

  tags = {
    Name = "k8-master"
  }
}
